package com.bank.app.transaction;

import android.content.Context;
import android.content.pm.PackageManager;
import android.os.Build;
import android.provider.Settings;
import android.util.Log;
import com.google.android.gms.common.ConnectionResult;
import com.google.android.gms.common.GoogleApiAvailability;
import java.io.BufferedReader;
import java.io.File;
import java.io.InputStreamReader;
import java.security.MessageDigest;
import java.util.concurrent.CompletableFuture;

public class DeviceSecurityChecker {
    private static final String TAG = "DeviceSecurityChecker";
    private final Context context;
    
    public DeviceSecurityChecker(Context context) {
        this.context = context;
    }
    
    public CompletableFuture<SecurityCheckResult> performSecurityChecks() {
        return CompletableFuture.supplyAsync(() -> {
            SecurityCheckResult.Builder builder = new SecurityCheckResult.Builder();
            
            // Check 1: Root detection
            boolean isRooted = isDeviceRooted();
            builder.setRooted(isRooted);
            if (isRooted) {
                Log.w(TAG, "Device appears to be rooted");
                builder.addReason("Device is rooted");
            }
            
            // Check 2: Emulator detection
            boolean isEmulator = isEmulator();
            builder.setEmulator(isEmulator);
            if (isEmulator) {
                Log.w(TAG, "Running on emulator");
                builder.addReason("Running on emulator");
            }
            
            // Check 3: Developer options enabled
            boolean devOptionsEnabled = isDeveloperOptionsEnabled();
            builder.setDeveloperOptionsEnabled(devOptionsEnabled);
            if (devOptionsEnabled) {
                Log.w(TAG, "Developer options enabled");
            }
            
            // Check 4: USB debugging enabled
            boolean usbDebuggingEnabled = isUsbDebuggingEnabled();
            builder.setUsbDebuggingEnabled(usbDebuggingEnabled);
            if (usbDebuggingEnabled) {
                Log.w(TAG, "USB debugging enabled");
                builder.addReason("USB debugging is enabled");
            }
            
            // Check 5: Google Play Services availability
            boolean playServicesAvailable = isGooglePlayServicesAvailable();
            builder.setPlayServicesAvailable(playServicesAvailable);
            if (!playServicesAvailable) {
                Log.w(TAG, "Google Play Services not available");
                builder.addReason("Google Play Services unavailable");
            }
            
            // Check 6: App signature verification
            boolean signatureValid = verifyAppSignature();
            builder.setSignatureValid(signatureValid);
            if (!signatureValid) {
                Log.w(TAG, "App signature verification failed");
                builder.addReason("App signature invalid");
            }
            
            // Check 7: Debuggable build
            boolean isDebuggable = isDebuggable();
            builder.setDebuggable(isDebuggable);
            if (isDebuggable) {
                Log.w(TAG, "App is debuggable");
            }
            
            // Generate device fingerprint
            String fingerprint = generateDeviceFingerprint();
            builder.setDeviceFingerprint(fingerprint);
            
            SecurityCheckResult result = builder.build();
            
            // Determine if device is secure enough for transactions
            boolean isSecure = !isRooted && !isEmulator && signatureValid && playServicesAvailable;
            result.setSecure(isSecure);
            
            return result;
        });
    }
    
    private boolean isDeviceRooted() {
        // Check for common root indicators
        String[] rootIndicators = {
            "/system/app/Superuser.apk",
            "/sbin/su",
            "/system/bin/su",
            "/system/xbin/su",
            "/data/local/xbin/su",
            "/data/local/bin/su",
            "/system/sd/xbin/su",
            "/system/bin/failsafe/su",
            "/data/local/su",
            "/su/bin/su"
        };
        
        for (String path : rootIndicators) {
            if (new File(path).exists()) {
                return true;
            }
        }
        
        // Check for su binary
        try {
            Process process = Runtime.getRuntime().exec(new String[]{"which", "su"});
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            if (reader.readLine() != null) {
                return true;
            }
        } catch (Exception e) {
            // Exception is expected on non-rooted devices
        }
        
        // Check for root management apps
        String[] rootApps = {
            "com.noshufou.android.su",
            "com.thirdparty.superuser",
            "eu.chainfire.supersu",
            "com.koushikdutta.superuser",
            "com.zachspong.temprootremovejb",
            "com.ramdroid.appquarantine",
            "com.topjohnwu.magisk"
        };
        
        PackageManager pm = context.getPackageManager();
        for (String packageName : rootApps) {
            try {
                pm.getPackageInfo(packageName, 0);
                return true;
            } catch (PackageManager.NameNotFoundException e) {
                // Package not found, continue
            }
        }
        
        return false;
    }
    
    private boolean isEmulator() {
        return Build.FINGERPRINT.startsWith("generic")
            || Build.FINGERPRINT.startsWith("unknown")
            || Build.MODEL.contains("google_sdk")
            || Build.MODEL.contains("Emulator")
            || Build.MODEL.contains("Android SDK built for x86")
            || Build.MANUFACTURER.contains("Genymotion")
            || (Build.BRAND.startsWith("generic") && Build.DEVICE.startsWith("generic"))
            || "google_sdk".equals(Build.PRODUCT)
            || Build.HARDWARE.contains("goldfish")
            || Build.HARDWARE.contains("ranchu");
    }
    
    private boolean isDeveloperOptionsEnabled() {
        return Settings.Global.getInt(context.getContentResolver(),
            Settings.Global.DEVELOPMENT_SETTINGS_ENABLED, 0) != 0;
    }
    
    private boolean isUsbDebuggingEnabled() {
        return Settings.Global.getInt(context.getContentResolver(),
            Settings.Global.ADB_ENABLED, 0) != 0;
    }
    
    private boolean isGooglePlayServicesAvailable() {
        GoogleApiAvailability apiAvailability = GoogleApiAvailability.getInstance();
        int resultCode = apiAvailability.isGooglePlayServicesAvailable(context);
        return resultCode == ConnectionResult.SUCCESS;
    }
    
    private boolean verifyAppSignature() {
        try {
            PackageManager pm = context.getPackageManager();
            String packageName = context.getPackageName();
            
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                android.content.pm.SigningInfo signingInfo = pm.getPackageInfo(
                    packageName, PackageManager.GET_SIGNING_CERTIFICATES).signingInfo;
                
                if (signingInfo.hasMultipleSigners()) {
                    // Multiple signers - verify each
                    android.content.pm.Signature[] signatures = signingInfo.getApkContentsSigners();
                    return verifySignatures(signatures);
                } else {
                    // Single signer
                    android.content.pm.Signature[] signatures = signingInfo.getSigningCertificateHistory();
                    return verifySignatures(signatures);
                }
            } else {
                android.content.pm.Signature[] signatures = pm.getPackageInfo(
                    packageName, PackageManager.GET_SIGNATURES).signatures;
                return verifySignatures(signatures);
            }
        } catch (Exception e) {
            Log.e(TAG, "Error verifying app signature", e);
            return false;
        }
    }
    
    private boolean verifySignatures(android.content.pm.Signature[] signatures) {
        try {
            // In production, compare against known valid signature hash
            // This is a placeholder - replace with actual signature verification
            for (android.content.pm.Signature signature : signatures) {
                MessageDigest md = MessageDigest.getInstance("SHA-256");
                byte[] digest = md.digest(signature.toByteArray());
                // Compare digest with expected value
                // For now, just verify signature exists
                if (digest.length > 0) {
                    return true;
                }
            }
            return false;
        } catch (Exception e) {
            Log.e(TAG, "Error verifying signatures", e);
            return false;
        }
    }
    
    private boolean isDebuggable() {
        return (context.getApplicationInfo().flags & android.content.pm.ApplicationInfo.FLAG_DEBUGGABLE) != 0;
    }
    
    private String generateDeviceFingerprint() {
        try {
            StringBuilder fingerprint = new StringBuilder();
            fingerprint.append(Build.BOARD).append(":");
            fingerprint.append(Build.BRAND).append(":");
            fingerprint.append(Build.DEVICE).append(":");
            fingerprint.append(Build.HARDWARE).append(":");
            fingerprint.append(Build.ID).append(":");
            fingerprint.append(Build.MANUFACTURER).append(":");
            fingerprint.append(Build.MODEL).append(":");
            fingerprint.append(Build.PRODUCT);
            
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(fingerprint.toString().getBytes());
            StringBuilder hexString = new StringBuilder();
            for (byte b : hash) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) hexString.append('0');
                hexString.append(hex);
            }
            return hexString.toString();
        } catch (Exception e) {
            return "unknown";
        }
    }
}

// AccountBalanceActivity.java
package com.bank.app.ui;

import android.os.Bundle;
import android.util.Log;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import com.bank.app.transaction.DeviceSecurityChecker;
import com.bank.app.transaction.SecurityCheckResult;
import com.bank.app.transaction.Transaction;
import com.bank.app.transaction.TransactionManager;
import com.bank.app.transaction.TransactionResult;
import java.text.NumberFormat;
import java.util.Locale;

public class AccountBalanceActivity extends AppCompatActivity {
    private static final String TAG = "AccountBalanceActivity";
    
    private TextView balanceTextView;
    private TextView securityStatusTextView;
    private EditText amountEditText;
    private EditText recipientEditText;
    private Button transferButton;
    private Button refreshButton;
    
    private TransactionManager transactionManager;
    private DeviceSecurityChecker securityChecker;
    private double currentBalance = 5000.00;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(getLayoutResourceId());
        
        initializeViews();
        transactionManager = new TransactionManager(this);
        securityChecker = new DeviceSecurityChecker(this);
        
        performInitialSecurityCheck();
        updateBalanceDisplay();
        setupListeners();
    }
    
    private void initializeViews() {
        balanceTextView = findViewById(getBalanceTextViewId());
        securityStatusTextView = findViewById(getSecurityStatusTextViewId());
        amountEditText = findViewById(getAmountEditTextId());
        recipientEditText = findViewById(getRecipientEditTextId());
        transferButton = findViewById(getTransferButtonId());
        refreshButton = findViewById(getRefreshButtonId());
    }
    
    private void performInitialSecurityCheck() {
        securityChecker.performSecurityChecks().thenAccept(result -> {
            runOnUiThread(() -> {
                updateSecurityStatus(result);
                if (!result.isSecure()) {
                    showSecurityWarning(result);
                }
            });
        }).exceptionally(ex -> {
            Log.e(TAG, "Security check failed", ex);
            runOnUiThread(() -> {
                securityStatusTextView.setText("Security Status: Unknown");
                Toast.makeText(this, "Unable to verify device security", Toast.LENGTH_LONG).show();
            });
            return null;
        });
    }
    
    private void updateSecurityStatus(SecurityCheckResult result) {
        if (result.isSecure()) {
            securityStatusTextView.setText("Security Status: Verified");
            securityStatusTextView.setTextColor(getResources().getColor(android.R.color.holo_green_dark));
        } else {
            securityStatusTextView.setText("Security Status: Warning");
            securityStatusTextView.setTextColor(getResources().getColor(android.R.color.holo_orange_dark));
        }
    }
    
    private void showSecurityWarning(SecurityCheckResult result) {
        String message = "Security concerns detected:\n" + result.getReason() +
            "\n\nTransactions may be restricted for your protection.";
        
        new androidx.appcompat.app.AlertDialog.Builder(this)
            .setTitle("Security Warning")
            .setMessage(message)
            .setPositiveButton("I Understand", null)
            .setNegativeButton("Contact Support", (dialog, which) -> {
                // Open support contact
            })
            .show();
    }
    
    private void setupListeners() {
        transferButton.setOnClickListener(v -> processTransfer());
        refreshButton.setOnClickListener(v -> {
            performInitialSecurityCheck();
            updateBalanceDisplay();
        });
    }
    
    private void processTransfer() {
        String amountStr = amountEditText.getText().toString();
        String recipient = recipientEditText.getText().toString();
        
        if (amountStr.isEmpty() || recipient.isEmpty()) {
            Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show();
            return;
        }
        
        try {
            double amount = Double.parseDouble(amountStr);
            
            if (amount <= 0) {
                Toast.makeText(this, "Invalid amount", Toast.LENGTH_SHORT).show();
                return;
            }
            
            if (amount > currentBalance) {
                Toast.makeText(this, "Insufficient balance", Toast.LENGTH_SHORT).show();
                return;
            }
            
            transferButton.setEnabled(false);
            transferButton.setText("Processing...");
            
            Transaction transaction = new Transaction.Builder()
                .setId(generateTransactionId())
                .setAmount(amount)
                .setRecipient(recipient)
                .setType(Transaction.Type.TRANSFER)
                .setTimestamp(System.currentTimeMillis())
                .build();
            
            transactionManager.processTransaction(transaction).thenAccept(result -> {
                runOnUiThread(() -> handleTransactionResult(result, amount));
            }).exceptionally(ex -> {
                runOnUiThread(() -> {
                    Toast.makeText(this, "Transaction failed: " + ex.getMessage(), 
                        Toast.LENGTH_LONG).show();
                    transferButton.setEnabled(true);
                    transferButton.setText("Transfer");
                });
                return null;
            });
            
        } catch (NumberFormatException e) {
            Toast.makeText(this, "Invalid amount format", Toast.LENGTH_SHORT).show();
        }
    }
    
    private void handleTransactionResult(TransactionResult result, double amount) {
        transferButton.setEnabled(true);
        transferButton.setText("Transfer");
        
        if (result.isSuccess()) {
            currentBalance -= amount;
            updateBalanceDisplay();
            amountEditText.setText("");
            recipientEditText.setText("");
            Toast.makeText(this, "Transfer successful", Toast.LENGTH_SHORT).show();
        } else {
            Toast.makeText(this, "Transfer failed: " + result.getMessage(), 
                Toast.LENGTH_LONG).show();
        }
    }
    
    private void updateBalanceDisplay() {
        NumberFormat currencyFormat = NumberFormat.getCurrencyInstance(Locale.US);
        balanceTextView.setText("Balance: " + currencyFormat.format(currentBalance));
    }
    
    private String generateTransactionId() {
        return "TXN" + System.currentTimeMillis();
    }
    
    // Placeholder methods for resource IDs
    private int getLayoutResourceId() {
        return android.R.layout.activity_list_item;
    }
    
    private int getBalanceTextViewId() {
        return android.R.id.text1;
    }
    
    private int getSecurityStatusTextViewId() {
        return android.R.id.text2;
    }
    
    private int getAmountEditTextId() {
        return android.R.id.edit;
    }
    
    private int getRecipientEditTextId() {
        return android.R.id.input;
    }
    
    private int getTransferButtonId() {
        return android.R.id.button1;
    }
    
    private int getRefreshButtonId() {
        return android.R.id.button2;
    }
}

