package com.bank.app.transaction;

public class Transaction {
    private String id;
    private double amount;
    private String recipient;
    private Type type;
    private long timestamp;
    private SecurityMetadata securityMetadata;
    
    public enum Type {
        TRANSFER, PAYMENT, WITHDRAWAL
    }
    
    private Transaction(Builder builder) {
        this.id = builder.id;
        this.amount = builder.amount;
        this.recipient = builder.recipient;
        this.type = builder.type;
        this.timestamp = builder.timestamp;
    }
    
    public String getId() { return id; }
    public double getAmount() { return amount; }
    public String getRecipient() { return recipient; }
    public Type getType() { return type; }
    public long getTimestamp() { return timestamp; }
    public SecurityMetadata getSecurityMetadata() { return securityMetadata; }
    
    public void setSecurityMetadata(SecurityMetadata metadata) {
        this.securityMetadata = metadata;
    }
    
    public static class Builder {
        private String id;
        private double amount;
        private String recipient;
        private Type type;
        private long timestamp;
        
        public Builder setId(String id) {
            this.id = id;
            return this;
        }
        
        public Builder setAmount(double amount) {
            this.amount = amount;
            return this;
        }
        
        public Builder setRecipient(String recipient) {
            this.recipient = recipient;
            return this;
        }
        
        public Builder setType(Type type) {
            this.type = type;
            return this;
        }
        
        public Builder setTimestamp(long timestamp) {
            this.timestamp = timestamp;
            return this;
        }
        
        public Transaction build() {
            return new Transaction(this);
        }
    }
}

